def convex_hull(arg1):
    points = arg1
    if len(points) <= 1:
        return points
    points = sorted(points)
    lower = []
    for p in points:
        while len(lower) >= 2 and cross(lower[-2], lower[-1], p) <= 0:
            lower.pop()
        lower.append(p)
    upper = []
    for p in reversed(points):
        while len(upper) >= 2 and cross(upper[-2], upper[-1], p) <= 0:
            upper.pop()
        upper.append(p)
    return lower[:-1] + upper[:-1]

def count_valid_parabolas(arg1):
    points = arg1
    n = len(points)
    if n < 2:
        return 0
    
    # Transform points to (x, y - x^2)
    transformed = transform_points(points)
    
    # Get convex hull of transformed points
    hull = convex_hull(transformed)
    
    # Create mapping from transformed points back to original indices
    point_to_indices = {}
    for i, (x, y) in enumerate(points):
        tx, ty = x, y - x*x
        if (tx, ty) not in point_to_indices:
            point_to_indices[(tx, ty)] = []
        point_to_indices[(tx, ty)].append(i)
    
    # Find hull points that correspond to original points
    hull_indices = set()
    for hx, hy in hull:
        if (hx, hy) in point_to_indices:
            hull_indices.update(point_to_indices[(hx, hy)])
    
    # Count valid parabolas - these are edges on the lower hull
    count = 0
    hull_points = []
    for hx, hy in hull:
        if (hx, hy) in point_to_indices:
            for idx in point_to_indices[(hx, hy)]:
                hull_points.append((points[idx], idx))
    
    # Sort hull points by x coordinate
    hull_points.sort(key=lambda x: x[0][0])
    
    # Count edges on lower hull between points with different x coordinates
    for i in range(len(hull_points)):
        for j in range(i + 1, len(hull_points)):
            p1, idx1 = hull_points[i]
            p2, idx2 = hull_points[j]
            
            if p1[0] != p2[0]:  # Different x coordinates
                # Check if this edge is on the lower hull
                x1, y1 = p1
                x2, y2 = p2
                
                # Check if all other points are above or on this parabola
                valid = True
                for k in range(n):
                    if k == idx1 or k == idx2:
                        continue
                    x3, y3 = points[k]
                    
                    # Calculate parabola value at x3
                    b = (y2 - y1 - x2*x2 + x1*x1) / (x2 - x1)
                    c = y1 - x1*x1 - b*x1
                    parabola_y = x3*x3 + b*x3 + c
                    
                    if y3 > parabola_y:
                        valid = False
                        break
                
                if valid:
                    count += 1
    
    return count

def main(arg1):
    lines = arg1.strip().split('\n')
    n = int(lines[0])
    points = []
    for i in range(1, n + 1):
        x, y = map(int, lines[i].split())
        points.append((x, y))
    
    result = count_valid_parabolas(points)
    return str(result)

